+fn generate_url_polyfill() -> String {
+    r#"// Browser polyfill for 'url'
+export const URL = globalThis.URL;
+export const URLSearchParams = globalThis.URLSearchParams;
+
+export function parse(urlStr) {
+  try {
+    var u = new URL(urlStr);
+    return {
+      protocol: u.protocol,
+      hostname: u.hostname,
+      port: u.port,
+      pathname: u.pathname,
+      search: u.search,
+      hash: u.hash,
+      host: u.host,
+      href: u.href,
+    };
+  } catch (e) {
