+export function promisify(fn) {
+  return function() {
+    var args = Array.prototype.slice.call(arguments);
+    return new Promise(function(resolve, reject) {
+      args.push(function(err, result) {
+        if (err) reject(err);
+        else resolve(result);
+      });
