+  return fmt.replace(/%[sdj%]/g, function(match) {
+    if (match === '%%') return '%';
+    var arg = args.shift();
+    if (match === '%s') return String(arg);
+    if (match === '%d') return Number(arg);
+    if (match === '%j') return JSON.stringify(arg);
+    return match;
+  });
